<?php
$renderCouponFields=function(array $item,array $categories,array $products,array $selectedCategories=[],array $selectedProducts=[],string $mode='include'):void{
$displayValue=$item['discount_type']==='fixed'?number_format((int)$item['discount_value']/100,2,'.',''):(int)$item['discount_value']; ?>
<?php if(!empty($item['id'])): ?><input type="hidden" name="coupon_id" value="<?= (int)$item['id'] ?>"><?php endif; ?>
<div class="admin-form-grid"><label>Cod<input name="code" required value="<?= e($item['code']??'') ?>"></label><label>Tip<select name="discount_type"><option value="percent" <?= ($item['discount_type']??'percent')==='percent'?'selected':'' ?>>Procent</option><option value="fixed" <?= ($item['discount_type']??'')==='fixed'?'selected':'' ?>>Sumă fixă</option></select></label><label>Valoare<input type="number" step="0.01" name="discount_value" min="0.01" required value="<?= e($displayValue?:'') ?>"></label><label>Minim comandă (lei)<input type="number" step="0.01" name="minimum_order" min="0" value="<?= number_format((int)($item['minimum_order_minor']??0)/100,2,'.','') ?>"></label><label>Reducere maximă (lei)<input type="number" step="0.01" name="maximum_discount" min="0" value="<?= $item['maximum_discount_minor']!==null?number_format((int)$item['maximum_discount_minor']/100,2,'.',''):'' ?>"></label><label>Utilizări totale maxime<input type="number" name="max_uses" min="0" value="<?= e($item['max_uses']??'') ?>"></label><label>Utilizări / client<input type="number" name="max_uses_per_user" min="0" value="<?= e($item['max_uses_per_user']??'') ?>"></label><label>Începe la<input type="datetime-local" name="starts_at" value="<?= !empty($item['starts_at'])?e(date('Y-m-d\TH:i',strtotime($item['starts_at']))):'' ?>"></label><label>Expiră la<input type="datetime-local" name="ends_at" value="<?= !empty($item['ends_at'])?e(date('Y-m-d\TH:i',strtotime($item['ends_at']))):'' ?>"></label><label>Regulă eligibilitate<select name="eligibility_mode"><option value="include" <?= $mode==='include'?'selected':'' ?>>Doar selecția de mai jos</option><option value="exclude" <?= $mode==='exclude'?'selected':'' ?>>Toate, mai puțin selecția</option></select></label></div>
<details class="coupon-eligibility"><summary>Produse și categorii eligibile</summary><div class="coupon-eligibility-grid"><label>Categorii<select name="category_ids[]" multiple size="7"><?php foreach($categories as $category): ?><option value="<?= (int)$category['id'] ?>" <?= in_array((int)$category['id'],$selectedCategories,true)?'selected':'' ?>><?= e($category['name']) ?></option><?php endforeach; ?></select></label><label>Produse<select name="product_ids[]" multiple size="7"><?php foreach($products as $product): ?><option value="<?= (int)$product['id'] ?>" <?= in_array((int)$product['id'],$selectedProducts,true)?'selected':'' ?>><?= e($product['name']) ?></option><?php endforeach; ?></select></label></div><p class="help">Ține Ctrl/Cmd pentru selecție multiplă. Dacă nu selectezi nimic, cuponul se aplică întregului catalog.</p></details>
<label class="toggle-switch"><input type="checkbox" name="is_active" value="1" <?= !isset($item['is_active'])||$item['is_active']?'checked':'' ?>><span class="switch-track"><i></i></span><b>Cupon activ</b></label><?php }; ?>
<section class="admin-page-head"><div><p class="eyebrow">MARKETING</p><h1>Cupoane și promoții</h1><p>Configurează valabilitatea, limitele și produsele eligibile.</p></div></section><div class="admin-two-columns"><section class="coupon-grid"><?php foreach($items as $item): ?><form class="admin-panel coupon-admin-card" method="post" action="<?= e(url('/admin/cupoane')) ?>"><?= csrf_field() ?><div class="panel-head"><div><span class="status-pill <?= $item['is_active']?'success':'' ?>"><?= $item['is_active']?'Activ':'Inactiv' ?></span><h2><?= e($item['code']) ?></h2></div><small><?= (int)$item['used_total'] ?> utilizări</small></div><?php $renderCouponFields($item,$categories,$products,$couponCategories[(int)$item['id']]??[],$couponProducts[(int)$item['id']]??[],$couponModes[(int)$item['id']]??'include'); ?><button class="admin-button" type="submit">Salvează modificările</button></form><?php endforeach; ?></section><aside><form class="admin-panel coupon-admin-card" method="post" action="<?= e(url('/admin/cupoane')) ?>"><?= csrf_field() ?><h2>Cupon nou</h2><?php $renderCouponFields(['discount_type'=>'percent','minimum_order_minor'=>0,'maximum_discount_minor'=>null,'is_active'=>1],$categories,$products); ?><button class="admin-button" type="submit">Creează cuponul</button></form></aside></div>